      "testable_assertion": "Any attempt to create a shipment missing either pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are strictly forward-only: Pending → InTransit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "State regression would corrupt operational data — dispatch records, tracking events, and audit trails depend on monotonic state progression. A parcel physically in transit cannot un-transit.",
      "testable_assertion": "Transitioning a shipment from InTransit back to Pending must be rejected. Transitioning from Delivered to any other state must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state. No further state changes are allowed on a delivered shipment.",
      "invariant": true,
      "invariant_justification": "Delivery is a physical finality — the parcel has been handed over. Altering state after delivery would break billing, proof-of-delivery records, and customer notifications.",
      "testable_assertion": "Any state change attempted on a shipment in Delivered state must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound reflects a physical/vehicle capacity constraint — violating it risks safety and equipment limits.",
      "testable_assertion": "Creating or updating a shipment with weight <= 0 or weight > 1000 must be rejected."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket is determined by weight: Standard for (0, 10] kg, Heavy for (10, 50] kg, Freight for (50, 1000] kg.",
