    {
      "id": "BR-6",
      "rule": "A newly created shipment starts in Pending state.",
      "invariant": true,
      "invariant_justification": "A shipment cannot be born already delivered or in transit — it must be pending dispatch first. This ensures the lifecycle begins at its logical origin.",
      "testable_assertion": "When a shipment is successfully created, its initial state must be Pending."
    }
